import React from "react"
import Header from "./Header"
import Footer from "./Footer"
import Note from "./Note"

function createNote(newNote) {
    <Note 
    noteTitle={newNote.title}
    noteContent={newNote.content}/>
}

function App() {
    return(
        <div>
            <Header/>
            {notes.map(createNote)}
            <Footer/>
        </div>
    );
}

export default App;
